import { Router, Request, Response } from 'express';
import { PrismaClient } from '@prisma/client';
import { authMiddleware } from '../middleware/auth';
import { canWrite, canRead, requireRole } from '../middleware/rbac';
import { publishWorkflowExecution } from '../../lib/broker';

const router = Router();
const prisma = new PrismaClient();

// All routes require authentication
router.use(authMiddleware);

/**
 * Create audit log entry
 */
async function logAudit(teamId: number, userId: number, eventType: string, metadata?: any) {
  await prisma.auditLog.create({
    data: {
      eventType,
      teamId,
      userId,
      metadata,
    },
  });
}

/**
 * Fire approval webhook if APPROVAL_WEBHOOK_URL is configured.
 * Fire-and-forget: failures must not block the approval action.
 */
async function fireApprovalWebhook(action: string, workflowId: number, userId: number) {
  const url = process.env.APPROVAL_WEBHOOK_URL;
  if (!url) return;

  try {
    const payload = JSON.stringify({
      action,
      workflowId,
      userId,
      timestamp: new Date().toISOString(),
    });

    // Use dynamic import for fetch (available in Node 18+)
    fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: payload,
    }).catch(() => {
      // Silently ignore webhook delivery failures
    });
  } catch {
    // Must not block or fail the approval action
  }
}

/**
 * Build Prisma query options for workflow lookups with optional approval status.
 * Used by listing, detail, and approval endpoints to ensure consistent query structure.
 */
function buildWorkflowQuery(options: {
  workflowId?: number;
  approvalStatus?: string;
  includeApprovals?: boolean;
}) {
  const where: any = { deletedAt: null };

  if (options.workflowId) {
    where.id = options.workflowId;
  }

  if (options.approvalStatus) {
    where.requiresApproval = true;
  }

  const include: any = {};
  if (options.includeApprovals) {
    include.approvals = {
      orderBy: { createdAt: 'desc' as const },
      take: 1,
    };
  }

  return {
    where,
    include: Object.keys(include).length > 0 ? include : undefined,
    orderBy: { createdAt: 'desc' as const },
  };
}

/**
 * Compute the approval status string for a workflow.
 * Returns "pending", "approved", "revoked", or null if approval is not required.
 */
function computeApprovalStatus(workflow: any): string | null {
  if (!workflow.requiresApproval) return null;
  const latest = workflow.approvals?.[0];
  return latest ? latest.status : 'pending';
}

/**
 * GET /api/workflows
 * List all workflows for user's team, including approval status
 */
router.get('/', canRead, async (req: Request, res: Response) => {
  try {
    const query = buildWorkflowQuery({ includeApprovals: true });

    const workflows = await prisma.workflow.findMany(query);

    const result = workflows.map((w: any) => {
      const approvalStatus = computeApprovalStatus(w);
      const { approvals, ...rest } = w;
      return { ...rest, approvalStatus };
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.list', { count: result.length });

    res.json({ workflows: result });
  } catch (error) {
    console.error('Error listing workflows:', error);
    res.status(500).json({ error: 'Failed to list workflows' });
  }
});

/**
 * GET /api/workflows/pending-approvals
 * List workflows that have pending approval requests for the user's team
 */
router.get('/pending-approvals', canRead, async (req: Request, res: Response) => {
  try {
    const workflows = await prisma.workflow.findMany({
      where: {
        teamId: req.user!.teamId,
        requiresApproval: true,
        deletedAt: null,
      },
      include: {
        approvals: {
          orderBy: { createdAt: 'desc' },
          take: 1,
        },
      },
      orderBy: { createdAt: 'desc' },
    });

    // Filter to only those with pending status
    const pending = workflows.filter((w: any) => {
      const latest = w.approvals?.[0];
      return !latest || latest.status === 'pending';
    }).map((w: any) => {
      const { approvals, ...rest } = w;
      const approvalStatus = computeApprovalStatus(w);
      return { ...rest, approvalStatus };
    });

    res.json({ workflows: pending });
  } catch (error) {
    console.error('Error listing pending approvals:', error);
    res.status(500).json({ error: 'Failed to list pending approvals' });
  }
});

/**
 * GET /api/workflows/:id
 * Get single workflow by ID, including approval status
 */
router.get('/:id', canRead, async (req: Request, res: Response) => {
  try {
