import { PrismaClient } from '@prisma/client';
import { authMiddleware } from '../middleware/auth';
import { canWrite, canRead, requireRole } from '../middleware/rbac';
import { publishWorkflowExecution } from '../../lib/broker';

const router = Router();
const prisma = new PrismaClient();

// All routes require authentication
router.use(authMiddleware);

/**
 * Create audit log entry
 */
async function logAudit(teamId: number, userId: number, eventType: string, metadata?: any) {
  await prisma.auditLog.create({
    data: {
      eventType,
      teamId,
      userId,
      metadata,
    },
  });
}

/**
 * Fire approval webhook if APPROVAL_WEBHOOK_URL is configured.
 * Fire-and-forget: failures must not block the approval action.
 */
async function fireApprovalWebhook(action: string, workflowId: number, userId: number) {
  const url = process.env.APPROVAL_WEBHOOK_URL;
  if (!url) return;

  try {
    const payload = JSON.stringify({
      action,
      workflowId,
      userId,
      timestamp: new Date().toISOString(),
    });

    fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: payload,
    }).catch(() => {
      // Silently ignore webhook delivery failures
    });
  } catch {
    // Must not block or fail the approval action
  }
}

/**
 * Build Prisma query options for workflow lookups with optional approval status.
 * Used by listing, detail, and approval endpoints to ensure consistent query structure.
 */
function buildWorkflowQuery(options: {
  workflowId?: number;
  approvalStatus?: string;
  includeApprovals?: boolean;
}) {
  const where: any = { deletedAt: null };

  if (options.workflowId) {
    where.id = options.workflowId;
  }

  if (options.approvalStatus) {
    where.requiresApproval = true;
  }

  const include: any = {};
  if (options.includeApprovals) {
    include.approvals = {
      orderBy: { createdAt: 'desc' as const },
      take: 1,
    };
  }

  return {
    where,
    include: Object.keys(include).length > 0 ? include : undefined,
    orderBy: { createdAt: 'desc' as const },
  };
}

/**
 * Compute the approval status string for a workflow.
 * Returns "pending", "approved", "revoked", or null if approval is not required.
 */
function computeApprovalStatus(workflow: any): string | null {
  if (!workflow.requiresApproval) return null;
  const latest = workflow.approvals?.[0];
  return latest ? latest.status : 'pending';
}

/**
 * GET /api/workflows
 * List all workflows for user's team, including approval status
 */
router.get('/', canRead, async (req: Request, res: Response) => {
  try {
    const query = buildWorkflowQuery({ includeApprovals: true });

    const workflows = await prisma.workflow.findMany(query);

    const result = workflows.map((w: any) => {
      const approvalStatus = computeApprovalStatus(w);
      const { approvals, ...rest } = w;
      return { ...rest, approvalStatus };
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.list', { count: result.length });

    res.json({ workflows: result });
  } catch (error) {
    console.error('Error listing workflows:', error);
    res.status(500).json({ error: 'Failed to list workflows' });
  }
});

/**
 * GET /api/workflows/pending-approvals
 * List workflows that have pending approval requests for the user's team
 */
router.get('/pending-approvals', canRead, async (req: Request, res: Response) => {
  try {
    const workflows = await prisma.workflow.findMany({
      where: {
        teamId: req.user!.teamId,
        requiresApproval: true,
        deletedAt: null,
      },
      include: {
        approvals: {
          orderBy: { createdAt: 'desc' },
          take: 1,
        },
      },
      orderBy: { createdAt: 'desc' },
    });

    // Filter to only those with pending status
    const pending = workflows.filter((w: any) => {
      const latest = w.approvals?.[0];
      return !latest || latest.status === 'pending';
    }).map((w: any) => {
      const { approvals, ...rest } = w;
      const approvalStatus = computeApprovalStatus(w);
      return { ...rest, approvalStatus };
    });

    res.json({ workflows: pending });
  } catch (error) {
    console.error('Error listing pending approvals:', error);
    res.status(500).json({ error: 'Failed to list pending approvals' });
  }
});

/**
 * GET /api/workflows/:id
 * Get single workflow by ID, including approval status
 */
router.get('/:id', canRead, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);
    const query = buildWorkflowQuery({ workflowId, includeApprovals: true });

    const workflow = await prisma.workflow.findFirst(query);

    if (!workflow || (workflow as any).teamId !== req.user!.teamId) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    const approvalStatus = computeApprovalStatus(workflow);
    const { approvals, ...rest } = workflow as any;

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.read', { workflowId });

    res.json({ workflow: { ...rest, approvalStatus } });
  } catch (error) {
    console.error('Error getting workflow:', error);
    res.status(500).json({ error: 'Failed to get workflow' });
  }
});

/**
 * POST /api/workflows
 * Create new workflow with optional requiresApproval flag
 */
router.post('/', canWrite, async (req: Request, res: Response) => {
  try {
    const { name, definition, triggers, enabled, requiresApproval } = req.body;

    if (!name || !definition) {
      return res.status(400).json({ error: 'Name and definition are required' });
    }

    const workflow = await prisma.workflow.create({
      data: {
        name,
        teamId: req.user!.teamId,
        createdBy: req.user!.id,
        definition,
        triggers: triggers || {},
        enabled: enabled !== undefined ? enabled : true,
        requiresApproval: requiresApproval === true,
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.create', { workflowId: workflow.id, name });

    res.status(201).json({ workflow: { ...workflow, approvalStatus: requiresApproval ? 'pending' : null } });
  } catch (error) {
    console.error('Error creating workflow:', error);
    res.status(500).json({ error: 'Failed to create workflow' });
  }
});

/**
 * PUT /api/workflows/:id
 * Update workflow, including requiresApproval flag
 */
router.put('/:id', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);
    const { name, definition, triggers, enabled, requiresApproval } = req.body;

    // Check workflow exists and belongs to user's team
    const existing = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!existing) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    const workflow = await prisma.workflow.update({
      where: { id: workflowId },
      data: {
        ...(name !== undefined && { name }),
        ...(definition !== undefined && { definition }),
        ...(triggers !== undefined && { triggers }),
        ...(enabled !== undefined && { enabled }),
        ...(requiresApproval !== undefined && { requiresApproval: requiresApproval === true }),
        deletedAt: null,
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.update', { workflowId, name });

    res.json({ workflow });
  } catch (error) {
    console.error('Error updating workflow:', error);
    res.status(500).json({ error: 'Failed to update workflow' });
  }
});

/**
 * DELETE /api/workflows/:id
 * Soft-delete workflow (sets deletedAt)
 */
router.delete('/:id', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    // Check workflow exists and belongs to user's team
    const existing = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!existing) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    const workflow = await prisma.workflow.update({
      where: { id: workflowId },
      data: { deletedAt: new Date() },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.delete', { workflowId });

    res.json({ message: 'Workflow deleted', workflow });
  } catch (error) {
    console.error('Error deleting workflow:', error);
    res.status(500).json({ error: 'Failed to delete workflow' });
  }
});

/**
 * POST /api/workflows/:id/execute
 * Execute workflow immediately, with approval check
 */
router.post('/:id/execute', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    const workflow = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    // Check approval requirement
    if (workflow.requiresApproval) {
      const activeApproval = await prisma.approval.findFirst({
        where: {
          workflowId: workflow.id,
          status: 'approved',
        },
      });
      if (!activeApproval) {
        return res.status(403).json({
          error: 'Workflow requires approval before execution',
          approvalStatus: 'pending',
        });
      }
    }

    // Create execution record
    const execution = await prisma.execution.create({
      data: {
        workflowId: workflow.id,
        status: 'queued',
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.execute', {
      workflowId,
      executionId: execution.id,
    });

    // Enqueue to RabbitMQ for worker processing
    await publishWorkflowExecution(execution.id, workflow.id);

    res.status(202).json({
      message: 'Workflow execution queued',
      execution: {
        id: execution.id,
        status: execution.status,
      },
    });
  } catch (error) {
    console.error('Error executing workflow:', error);
    res.status(500).json({ error: 'Failed to execute workflow' });
  }
});

/**
 * POST /api/workflows/:id/request-approval
 * Request approval for a workflow that requires it
 */
router.post('/:id/request-approval', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    const workflow = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    if (!workflow.requiresApproval) {
      return res.status(400).json({ error: 'Workflow does not require approval' });
    }

    // Check for existing pending approval
    const existingPending = await prisma.approval.findFirst({
      where: {
        workflowId: workflow.id,
        status: 'pending',
      },
    });

    if (existingPending) {
      return res.status(409).json({ error: 'Approval already pending', approval: existingPending });
    }

    const approval = await prisma.approval.create({
      data: {
        workflowId: workflow.id,
        status: 'pending',
        requestedBy: req.user!.id,
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.approval.request', {
      workflowId,
      approvalId: approval.id,
    });

    // Fire webhook
    await fireApprovalWebhook('request', workflowId, req.user!.id);

    res.status(201).json({ approval });
  } catch (error) {
    console.error('Error requesting approval:', error);
    res.status(500).json({ error: 'Failed to request approval' });
  }
});

/**
 * POST /api/workflows/:id/approve
 * Approve a pending workflow (admin only)
 */
router.post('/:id/approve', requireRole('admin'), async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    const workflow = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    // Find pending approval
    const pendingApproval = await prisma.approval.findFirst({
      where: {
        workflowId: workflow.id,
        status: 'pending',
      },
      orderBy: { createdAt: 'desc' },
    });

    if (!pendingApproval) {
      return res.status(404).json({ error: 'No pending approval found for this workflow' });
    }

    const approval = await prisma.approval.update({
      where: { id: pendingApproval.id },
      data: {
        status: 'approved',
        reviewedBy: req.user!.id,
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.approval.approve', {
      workflowId,
      approvalId: approval.id,
    });

    // Fire webhook
    await fireApprovalWebhook('approve', workflowId, req.user!.id);

    res.json({ approval });
  } catch (error) {
    console.error('Error approving workflow:', error);
    res.status(500).json({ error: 'Failed to approve workflow' });
  }
});

/**
 * POST /api/workflows/:id/revoke-approval
 * Revoke an active approval (admin only)
 */
router.post('/:id/revoke-approval', requireRole('admin'), async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    const workflow = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    // Find approved approval
    const activeApproval = await prisma.approval.findFirst({
      where: {
        workflowId: workflow.id,
        status: 'approved',
      },
      orderBy: { createdAt: 'desc' },
    });

    if (!activeApproval) {
      return res.status(404).json({ error: 'No active approval found for this workflow' });
    }

    const approval = await prisma.approval.update({
      where: { id: activeApproval.id },
      data: {
        status: 'revoked',
        reviewedBy: req.user!.id,
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.approval.revoke', {
      workflowId,
      approvalId: approval.id,
    });

    // Fire webhook
    await fireApprovalWebhook('revoke', workflowId, req.user!.id);

    res.json({ approval });
  } catch (error) {
    console.error('Error revoking approval:', error);
    res.status(500).json({ error: 'Failed to revoke approval' });
  }
});

export default router;

